INSERT INTO public."NewsArticle" VALUES ('cmnuwohyy006wwrhpckv2n0vn', 'ABBA Voyage reaches “incredible milestone” of 4million visitors', 'abba-voyage-reaches-incredible-milestone-of-4million-visitors', 'ABBA have celebrated the “incredible milestone” of welcoming the four millionth visitor to their Voyage live show. READ MORE: ABBA Voyage live in London: an epic avatar mega-mix from a brave new world The groundbreaking concert residency sees digital CGI versions of the four members of ABBA performing in the purpose-built ABBA Arena in East London, and since launching in 2022, four million people have been in attendance. Voyage passed the one million visitor mark in April 2023, and as...', 'https://www.nme.com/news/music/abba-voyage-reaches-incredible-milestone-of-4million-visitors-3939710?utm_source=rss&utm_medium=rss&utm_campaign=abba-voyage-reaches-incredible-milestone-of-4million-visitors', 'https://www.nme.com/wp-content/uploads/2026/04/ABBA_Johan_Persson.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-11 18:32:52', '2026-04-11 22:27:59.866', '2026-04-11 22:27:59.866', false, 'via NME', NULL);
INSERT INTO public."NewsArticle" VALUES ('cmnuwohz2006xwrhpek6vizoh', 'Labrinth explains ‘Euphoria’ season three departure: “I don’t let people treat me like shit”', 'labrinth-explains-euphoria-season-three-departure-i-don-t-let-people-treat-me-like-shit', 'Labrinth has explained his departure from Euphoria season three, saying he will not “let people treat me like shit”. The long-awaited third season of the HBO show is launching tomorrow night (April 12), but Labrinth revealed last month that he would not be contributing to the score, despite being closely associated with both previous seasons. The musician, real name Timothy Lee McKenzie, hit out at the industry, his record label and Euphoria itself, writing in a since-deleted Instagram post: “I’M...', 'https://www.nme.com/news/tv/labrinth-explains-euphoria-season-three-departure-i-dont-let-people-treat-me-like-shit-3939705?utm_source=rss&utm_medium=rss&utm_campaign=labrinth-explains-euphoria-season-three-departure-i-dont-let-people-treat-me-like-shit', 'https://www.nme.com/wp-content/uploads/2026/04/labrinth_paris_2025.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-11 17:37:23', '2026-04-11 22:27:59.87', '2026-04-11 22:27:59.87', false, 'via NME', NULL);
INSERT INTO public."NewsArticle" VALUES ('cmnuwohyj006uwrhprat0gujb', 'Check out The Rolling Stones’ taster of bluesy new music as The Cockroaches', 'check-out-the-rolling-stones-taster-of-bluesy-new-music-as-the-cockroaches', 'The Rolling Stones have shared a taster of new music under the name The Cockroaches – check it out below. READ MORE: The Rolling Stones – ‘Hackney Diamonds’ review: they’ve still got it Rumours have been circling in recent weeks that the rock legends are planning on making an announcement of new music, with cryptic posters being spotted around London. All of the clues suggested that they would be using the alternative name The Cockroaches, an alias that Mick Jagger...', 'https://www.nme.com/news/music/check-out-the-rolling-stones-taster-of-bluesy-new-music-as-the-cockroaches-3939719?utm_source=rss&utm_medium=rss&utm_campaign=check-out-the-rolling-stones-taster-of-bluesy-new-music-as-the-cockroaches', 'https://www.nme.com/wp-content/uploads/2026/04/rolling_stones_live.jpg', true, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-11 21:31:36', '2026-04-11 22:27:59.851', '2026-04-12 12:53:04.319', false, 'via NME', NULL);
