INSERT INTO public."NewsArticle" VALUES ('cmnp43rvz000t07hpw2yvtpcu', 'Melvin Benn says Pepsi originally approved and “signed off” on Kanye West headlining Wireless before pulling out as sponsor', 'melvin-benn-says-pepsi-originally-approved-and-signed-off-on-kanye-west-headlining-wireless-before-p', 'Festival Republic boss Melvin Benn has claimed that Pepsi originally approved and “signed off” on the decision to have Kanye West headline the now-cancelled Wireless Festival, before pulling out as a sponsor over the weekend. The rapper was confirmed last week to be the headliner for all three nights of the London festival, and the gigs were advertised as a journey through his “most iconic records”. The booking sparked widespread criticism due to Ye’s history of anti-Semitism, and Prime Minister...', 'https://www.nme.com/news/music/melvin-benn-says-pepsi-signed-off-kanye-west-headlining-wireless-before-pulling-out-as-sponsor-3938943?utm_source=rss&utm_medium=rss&utm_campaign=melvin-benn-says-pepsi-signed-off-kanye-west-headlining-wireless-before-pulling-out-as-sponsor', 'https://www.nme.com/wp-content/uploads/2026/04/ye@2000x1270.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-07 15:02:58', '2026-04-07 21:09:12.815', '2026-04-07 21:09:12.815', false, NULL, NULL);
INSERT INTO public."NewsArticle" VALUES ('cmnp43rw3000u07hprhn898fb', 'Rostam shares cover of former band Vampire Weekend’s ‘Young Lion’', 'rostam-shares-cover-of-former-band-vampire-weekend-s-young-lion', 'Rostam has shared a new version of Vampire Weekend‘s ‘Young Lion’ – you can listen to it below. READ MORE: Vampire Weekend – ‘Only God Was Above Us’ review: back to the Big Apple The track originally featured at the end of the band’s 2013 album ‘Modern Vampires Of The City’. Is was the only Vampire Weekend song where Rostam was the sole lead vocalist and writer and was the last to feature on the band’s album. He quit Vampire...', 'https://www.nme.com/news/music/rostam-shares-cover-of-former-band-vampire-weekends-young-lion-3938899?utm_source=rss&utm_medium=rss&utm_campaign=rostam-shares-cover-of-former-band-vampire-weekends-young-lion', 'https://www.nme.com/wp-content/uploads/2026/04/2026_rostam_anyabondell_2000x1270.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-07 14:33:11', '2026-04-07 21:09:12.819', '2026-04-07 21:09:12.819', false, NULL, NULL);
INSERT INTO public."NewsArticle" VALUES ('cmnp43rw6000v07hphoe4k7bs', 'Wireless Festival cancelled after UK government block Kanye West from entering country', 'wireless-festival-cancelled-after-uk-government-block-kanye-west-from-entering-country', 'Kanye West‘s Wireless Festival appearance has been cancelled after the rapper was blocked from travelling to the UK by the government. The rapper, who now goes by Ye, was announced last week as the headliner for all three nights of the festival in London’s Finsbury Park in July, with the shows being described as a three-night journey through his “most iconic records”. The booking has prompted widespread criticism, including from Prime Minister Sir Keir Starmer, who said it is “deeply...', 'https://www.nme.com/news/music/kanye-west-blocked-from-travelling-to-the-uk-following-wireless-festival-controversy-3938911?utm_source=rss&utm_medium=rss&utm_campaign=kanye-west-blocked-from-travelling-to-the-uk-following-wireless-festival-controversy', 'https://www.nme.com/wp-content/uploads/2026/04/2026_kanye_getty_2000x1270.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-07 12:59:12', '2026-04-07 21:09:12.822', '2026-04-07 21:09:12.822', false, NULL, NULL);
INSERT INTO public."NewsArticle" VALUES ('cmnp43rw9000w07hpw8l4thsd', 'Ladysmith Black Mambazo’s “wise elder” Albert Mazibuko dies, aged 77: “What a legend, he and his group took the world by storm”', 'ladysmith-black-mambazo-s-wise-elder-albert-mazibuko-dies-aged-77-what-a-legend-he-and-his-group-too', 'Tributes have been paid as Albert Mazibuko, from the iconic South African group Ladysmith Black Mambazo, has died aged 77. The musician joined the group back in 1969, and remained as part of the line-up for 55 years. This included the five instances where the collective went on to win Grammy Awards, and when they also featured on Paul Simon’s acclaimed 1986 ‘Graceland’ album. His passing was confirmed on Sunday (April 5), and came after a short illness. “It is...', 'https://www.nme.com/news/music/ladysmith-black-mambazos-wise-elder-albert-mazibuko-dies-aged-77-3938905?utm_source=rss&utm_medium=rss&utm_campaign=ladysmith-black-mambazos-wise-elder-albert-mazibuko-dies-aged-77', 'https://www.nme.com/wp-content/uploads/2026/04/Albert-Mazibuko@2000x1270.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-07 12:36:53', '2026-04-07 21:09:12.825', '2026-04-07 21:09:12.825', false, NULL, NULL);
INSERT INTO public."NewsArticle" VALUES ('cmnp43rwc000x07hpt9fm6tjo', 'Fred Again.. B2B with Thomas Bangalter DJ mix from Alexandra Palace audio now available on Apple Music', 'fred-again-b2b-with-thomas-bangalter-dj-mix-from-alexandra-palace-audio-now-available-on-apple-music', 'Fred Again..’s B2B with Daft Punk icon Thomas Bangalter is now available to stream on Apple Music. READ MORE: Fred Again.. – ‘USB002’ review: a flow state of impulsive floor-fillers The live set took place on February 27 as the final UK stop on Fred’s huge ‘USB002’ tour, which kicked off at the start of the year, and saw him perform with a different special guest each night. Up until that point, guests had included Underworld, Mike Skinner, Joy Anonymous,...', 'https://www.nme.com/news/music/fred-again-b2b-with-thomas-bangalter-dj-mix-from-alexandra-palace-audio-now-available-on-apple-music-3938893?utm_source=rss&utm_medium=rss&utm_campaign=fred-again-b2b-with-thomas-bangalter-dj-mix-from-alexandra-palace-audio-now-available-on-apple-music', 'https://www.nme.com/wp-content/uploads/2026/04/fred-bangalter@2000x1270.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-07 11:59:42', '2026-04-07 21:09:12.828', '2026-04-07 21:09:12.828', false, NULL, NULL);
INSERT INTO public."NewsArticle" VALUES ('cmnp43rwg000y07hpe0h6t4uv', 'Watch Pet Shop Boys debut deep cuts and air rarities at first night of “obscure” song London residency', 'watch-pet-shop-boys-debut-deep-cuts-and-air-rarities-at-first-night-of-obscure-song-london-residency', 'Pet Shop Boys have kicked off their ‘Obscure’ intimate live shows in London, and broke out some deep cuts and rarities for the first time. Check out footage and the setlist below. READ MORE: Pet Shop Boys: “This is our queer album” The NME Godlike Genius alumni announced last year that they would be playing five shows at London’s Electric Ballroom in the spring, which would see them perform a setlist featuring only non-single album tracks and B-sides. Entitled ‘Obscure...', 'https://www.nme.com/news/music/watch-pet-shop-boys-debut-deep-cuts-and-air-rarities-at-first-night-of-obscure-song-london-residency-3938874?utm_source=rss&utm_medium=rss&utm_campaign=watch-pet-shop-boys-debut-deep-cuts-and-air-rarities-at-first-night-of-obscure-song-london-residency', 'https://www.nme.com/wp-content/uploads/2026/04/pet-shop-boys@2000x1270.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-07 11:26:26', '2026-04-07 21:09:12.832', '2026-04-07 21:09:12.832', false, NULL, NULL);
INSERT INTO public."NewsArticle" VALUES ('cmnp43rwj000z07hpcpcqxum4', 'Harry Styles shares indie-packed line-up for his curated Meltdown 2026', 'harry-styles-shares-indie-packed-line-up-for-his-curated-meltdown-2026', 'Harry Styles has shared an indie-packed line-up for his forthcoming Meltdown 2026 curation. Read More: Harry Styles – ‘Kiss All The Time. Disco, Occasionally’ review: pop superstar lets the light in The ‘Aperture‘ singer’s takeover at London’s Southbank Centre from Thursday June 11 until Sunday June 21, was confirmed last month. Now, along with confirmation of Styles’ own headline show at the Royal Festival Hall on March 16, a host of artists have joined the bill including Warpaint who will...', 'https://www.nme.com/news/music/harry-styles-shares-indie-packed-line-up-for-his-curated-meltdown-2026-3938855?utm_source=rss&utm_medium=rss&utm_campaign=harry-styles-shares-indie-packed-line-up-for-his-curated-meltdown-2026', 'https://www.nme.com/wp-content/uploads/2026/02/live-harry-styles-southbank.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-07 11:00:42', '2026-04-07 21:09:12.835', '2026-04-07 21:09:12.835', false, NULL, NULL);
INSERT INTO public."NewsArticle" VALUES ('cmnp43rwm001007hpwba4eauu', 'Jewish groups respond to Kanye West’s offer to meet – but say he still shouldn’t play Wireless', 'jewish-groups-respond-to-kanye-west-s-offer-to-meet-but-say-he-still-shouldn-t-play-wireless', 'Multiple Jewish groups have responded to Kanye West’s offer to meet and discuss his history of anti-Semitic comments, and said that he should not play at Wireless Festival. The rapper has a history of making anti-Semitic remarks on social media and in interviews. Recently, he was announced last week as the headliner for all three nights of the festival in London’s Finsbury Park in July, with the shows being described as a three-night journey through his “most iconic records”. Unsurprisingly,...', 'https://www.nme.com/news/music/jewish-groups-respond-to-kanye-wests-offer-to-meet-but-say-he-still-shouldnt-play-wireless-3938858?utm_source=rss&utm_medium=rss&utm_campaign=jewish-groups-respond-to-kanye-wests-offer-to-meet-but-say-he-still-shouldnt-play-wireless', 'https://www.nme.com/wp-content/uploads/2026/04/kanye@2000x1270.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-07 10:32:01', '2026-04-07 21:09:12.838', '2026-04-07 21:09:12.838', false, NULL, NULL);
