INSERT INTO public."NewsArticle" VALUES ('cmnuwohzp0073wrhpb6u3ooq9', 'Turnstile open Coachella set with recording of Brendan Yates’ father after band’s former guitarist was arrested for his attempted murder', 'turnstile-open-coachella-set-with-recording-of-brendan-yates-father-after-band-s-former-guitarist-wa', 'Turnstile kicked off their Coachella set by addressing news that their former guitarist Brady Ebert hit singer Brendan Yates’ father with his car. READ MORE: Turnstile – ‘Never Enough’ review: heartfelt hardcore poptimism Earlier this month, reports emerged that Ebert, who parted ways with Turnstile in 2022, had been arrested for attempted second-degree murder and first-degree assault, and it later transpired that Ebert was said to have run over vocalist Yates’ father, William, with his car. According to The Baltimore...', 'https://www.nme.com/news/music/turnstile-open-coachella-set-with-recording-of-brendan-yates-father-after-bands-former-guitarist-was-arrested-for-his-attempted-murder-3939624?utm_source=rss&utm_medium=rss&utm_campaign=turnstile-open-coachella-set-with-recording-of-brendan-yates-father-after-bands-former-guitarist-was-arrested-for-his-attempted-murder', 'https://www.nme.com/wp-content/uploads/2026/04/live-tunstile-coachella.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-11 09:48:46', '2026-04-11 22:27:59.893', '2026-04-11 22:27:59.893', false, 'via NME', NULL);
