INSERT INTO public."NewsArticle" VALUES ('cmnvoxemv000nwvhpwni5b18m', 'Purity Ring – “lemonlime”', 'purity-ring-lemonlime', 'A new Purity Ring single? I’m not about to pass on that. As soon as Megan James’ voice beams into “lemonlime,” I’m locked in. It’s a long way from the eerie sound of Shrines, but there’s still something extraterrestrial about the way James’ voice moves amidst Corin Roddick’s synthetic computer-pop environment. They’re calling the sound… The post Purity Ring – “lemonlime” appeared first on Stereogum.', 'https://stereogum.com/2495451/purity-ring-lemonlime/music/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/unnamed-2026-04-10T135438.460.png', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-10 18:08:10', '2026-04-12 11:38:44.695', '2026-04-12 11:38:44.695', false, 'Stereogum', NULL);
