INSERT INTO public."NewsArticle" VALUES ('cmnvoxfim000owvhp3bsdwpd4', 'Kehlani – “Back And Forth” (Feat. Missy Elliott)', 'kehlani-back-and-forth-feat-missy-elliott', 'Kehlani is following up the massive success of “Folded” with a new self-titled album due later this month. The album has “Folded” and “Out The Window,” and today we get a third preview with a noteworthy special guest. None other than Missy “Misdemeanor” Elliott graces “Back And Forth,” Kehlani’s appealing new single out today. Miss… The post Kehlani – “Back And Forth” (Feat. Missy Elliott) appeared first on Stereogum.', 'https://stereogum.com/2495446/kehlani-back-and-forth-feat-missy-elliott/music/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/unnamed-2026-04-10T132023.955-1.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-10 17:34:49', '2026-04-12 11:38:45.838', '2026-04-12 11:38:45.838', false, 'Stereogum', NULL);
INSERT INTO public."NewsArticle" VALUES ('cmnvmcpme0009wvhpdxf55eyu', 'Sabrina Carpenter apologises after mistaking Zaghrouta for yodel during Coachella set', 'sabrina-carpenter-apologises-after-mistaking-zaghrouta-for-yodel-during-coachella-set', 'Sabrina Carpenter has issued an apology after mistaking Zaghrouta, a celebratory Arabic chant, for a yodel during her headlining Coachella set. READ MORE: Sabrina Carpenter live in London: A testament to playing the long game to pop superstardom In a viral clip from Friday night’s (April 10) performance, an audience member can be making a high-pitched cheer she struggled to hear clearly over the crowd. “I think I heard someone yodel,” she said from the stage while she sat behind...', 'https://www.nme.com/news/music/sabrina-carpenter-apologises-after-mistaking-zaghrouta-for-yodel-during-coachella-set-3939738?utm_source=rss&utm_medium=rss&utm_campaign=sabrina-carpenter-apologises-after-mistaking-zaghrouta-for-yodel-during-coachella-set', 'https://www.nme.com/wp-content/uploads/2026/04/live-sabrina-carpneter-coachella.jpg', true, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-12 07:28:40', '2026-04-12 10:26:39.926', '2026-04-12 12:52:59.916', false, 'via NME', NULL);
