INSERT INTO public."NewsArticle" VALUES ('cmns1gboa0009wshpg2pcv9ul', 'NASA reveals Artemis II crew’s official wake-up songs playlist with Chappell Roan, Queen, David Bowie, Glass Animals and more', 'nasa-reveals-artemis-ii-crew-s-official-wake-up-songs-playlist-with-chappell-roan-queen-david-bowie-', 'NASA has revealed the playlist of wake-up songs made for the Artemis II crew, featuring the likes of Chappell Roan, Queen, David Bowie, Glass Animals and more. READ MORE: Chappell Roan: the pop supernova who feels like one of the ‘Drag Race’ girls The 10-day mission mission from NASA began on April 1 and sees a crew of four astronauts embark on journey around the moon and back. It is the first time humans have attempted the feat in over...', 'https://www.nme.com/news/music/nasa-reveals-artemis-ii-crews-official-wake-up-songs-playlist-with-chappell-roan-queen-david-bowie-glass-animals-and-more-3939336?utm_source=rss&utm_medium=rss&utm_campaign=nasa-reveals-artemis-ii-crews-official-wake-up-songs-playlist-with-chappell-roan-queen-david-bowie-glass-animals-and-more', 'https://www.nme.com/wp-content/uploads/2026/04/nasa@2000x1270.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-09 15:47:00', '2026-04-09 22:18:18.01', '2026-04-09 22:18:18.01', false, NULL, NULL);
INSERT INTO public."NewsArticle" VALUES ('cmns1gboe000awshpkwp3rxft', 'LIDO Festival cancels CMAT and Bombay Bicycle Club days, reschedules Maribou State', 'lido-festival-cancels-cmat-and-bombay-bicycle-club-days-reschedules-maribou-state', 'LIDO Festival has rescheduled its Maribou State headline show and cancelled the days topped by CMAT and Bombay Bicycle Club due to concerns about the grounds at Victoria Park. READ MORE: Charli XCX’s Partygirl live in London: celebrating the community and creators of ‘Brat’ summer The East London festival launched last year after being announced in late 2024. It is run by AEG Presents, who also organise All Points East, BST Hyde Park, Forwards and more. It was set to...', 'https://www.nme.com/news/music/lido-festival-cancels-cmat-bombay-bicycle-club-performances-reschedules-maribou-state-3939333?utm_source=rss&utm_medium=rss&utm_campaign=lido-festival-cancels-cmat-bombay-bicycle-club-performances-reschedules-maribou-state', 'https://www.nme.com/wp-content/uploads/2025/06/NMEAR_NME-GLASTO-2025_CMAT_Pyramid_AFord-620828.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-09 15:00:09', '2026-04-09 22:18:18.014', '2026-04-09 22:18:18.014', false, NULL, NULL);
