INSERT INTO public."NewsArticle" VALUES ('cmns1gbom000cwshpo8te5wox', 'Doja Cat says she’s “tickled” by Madonna trolls: “You feel threatened by an older woman who can do her job forever?”', 'doja-cat-says-she-s-tickled-by-madonna-trolls-you-feel-threatened-by-an-older-woman-who-can-do-her-j', 'Doja Cat has defended Madonna against trolls, saying she’s “tickled” by people who “feel threatened by an older woman who can do her job forever”. READ MORE: Madonna on the cover: ”People pick on me. That’s just the way it is” The popstar and rapper took to TikTok to discuss claims that Madonna was “too old” to be on stage, saying she was “tickled and bothered” by such comments. “It’s interesting to me because you’re telling a musician who makes...', 'https://www.nme.com/news/music/doja-cat-says-shes-tickled-by-madonna-trolls-you-feel-threatened-by-an-older-woman-who-can-do-her-job-forever-3939303?utm_source=rss&utm_medium=rss&utm_campaign=doja-cat-says-shes-tickled-by-madonna-trolls-you-feel-threatened-by-an-older-woman-who-can-do-her-job-forever', 'https://www.nme.com/wp-content/uploads/2026/04/Doja-Cat-Madonna-2026.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-09 12:35:04', '2026-04-09 22:18:18.022', '2026-04-09 22:18:18.022', false, NULL, NULL);
