INSERT INTO public."NewsArticle" VALUES ('cmnvoxb6o000gwvhp4vi13fgg', 'Anyma Coachella Set Canceled Due To Wind', 'anyma-coachella-set-canceled-due-to-wind', 'Though the first day of Coachella was mostly a success, it wasn’t without problems. Anyma had been slated to perform at midnight, but the Italian-American DJ’s set was canceled last-minute due to severe weather conditions. The Indio festival shared a statement yesterday on social media that read: “Due to strong wind conditions affecting Anyma’s stage…', 'https://stereogum.com/2495497/anyma-coachella-set-canceled-due-to-wind/news/', 'https://lede-admin.stereogum.com/wp-content/uploads/sites/64/2026/04/anyma.jpg', false, false, NULL, 'cmnvox6z8000cwvhp36gsp99j', '2026-04-11 16:24:29', '2026-04-12 11:38:40.224', '2026-04-12 12:52:45.435', false, 'Stereogum', NULL);
