INSERT INTO public."NewsArticle" VALUES ('cmnz6z0360012xphpmrbh3261', 'Irish musician Moya Brennan dies aged 73', 'irish-musician-moya-brennan-dies-aged-73', 'Moya Brennan, best known as the lead singer of the Grammy and BAFTA-winning group Clannad, died peacefully yesterday, surrounded by her family, at the age of 73.', 'https://www.rte.ie/entertainment/2026/0414/1568068-moya-brennan-clannad/', 'https://www.rte.ie/images/002436e4-1600.jpg', false, false, NULL, 'cmns3qc5u0000idhpe8f9i7uq', '2026-04-14 05:01:20', '2026-04-14 22:27:10.77', '2026-04-14 22:27:10.77', false, 'via RTE Music', NULL);
