INSERT INTO public."NewsArticle" VALUES ('cmnz6z1bp0014xphpkn67ouaj', 'Jorginho calls Chappell Roan clash a ''misunderstanding''', 'jorginho-calls-chappell-roan-clash-a-misunderstanding', 'Former Premier League footballer Jorginho has walked back claims linking Chappell Roan to a hotel confrontation in Sao Paulo involving a security guard and his 11-year-old stepdaughter, labelling the incident a "misunderstanding".', 'https://www.rte.ie/entertainment/2026/0414/1568079-jorginho-calls-chappell-roan-clash-a-misunderstanding/', 'https://www.rte.ie/images/00241905-1600.jpg', false, false, NULL, 'cmns3qc5u0000idhpe8f9i7uq', '2026-04-14 05:34:02', '2026-04-14 22:27:12.373', '2026-04-14 22:27:12.373', false, 'via RTE Music', NULL);
INSERT INTO public."NewsArticle" VALUES ('cmnz6z1cg0015xphpfeq5gxm6', 'Oasis among acts set for Rock and Roll Hall of Fame', 'oasis-among-acts-set-for-rock-and-roll-hall-of-fame', 'Oasis and Phil Collins are among the acts to be inducted into the Rock and Roll Hall of Fame this year, alongside heavy metal band Iron Maiden.', 'https://www.rte.ie/entertainment/2026/0414/1568080-oasis-among-acts-set-for-rock-and-roll-hall-of-fame/', 'https://www.rte.ie/images/00241b54-1600.jpg', false, false, NULL, 'cmns3qc5u0000idhpe8f9i7uq', '2026-04-14 05:44:50', '2026-04-14 22:27:12.4', '2026-04-14 22:27:12.4', false, 'via RTE Music', NULL);
