INSERT INTO public."NewsArticle" VALUES ('cmnz6z6ht001vxphpc0xy4icg', 'Asha Bhosle, Beloved Indian Singer, Dies at 92', 'asha-bhosle-beloved-indian-singer-dies-at-92', 'Thousands gathered for the world-renowned singer and Bollywood giant’s funeral in Mumbai', 'https://pitchfork.com/news/asha-bhosle-beloved-indian-singer-dies-at-92/', 'https://media.pitchfork.com/photos/69dd099ba79466e3bf488326/16:9/w_1280,c_limit/asha-bhosle.jpg', false, false, NULL, 'cmnkctw1m000jplhpezzt5352', '2026-04-13 15:51:55', '2026-04-14 22:27:19.073', '2026-04-14 22:27:19.073', false, 'via Pitchfork', NULL);
INSERT INTO public."NewsArticle" VALUES ('cmnz6z4aw001dxphpti5bic35', 'Launch date for KISS’ Las Vegas avatar show revealed – set to feature “new songs”', 'launch-date-for-kiss-las-vegas-avatar-show-revealed-set-to-feature-new-songs', 'The launch date for KISS’ Las Vegas avatar shows has been revealed, and it looks like the shows will include “new songs”. READ MORE: ABBA Voyage live in London: an epic avatar mega-mix from a brave new world At the final show of their farewell tour in Madison Square Garden in December 2023, the band shared that their “new era” would involve live shows where they would be replaced by their digital avatars. The holograms also debuted at that gig,...', 'https://www.nme.com/news/music/launch-date-for-kiss-las-vegas-avatar-show-revealed-set-to-feature-new-songs-3940345?utm_source=rss&utm_medium=rss&utm_campaign=launch-date-for-kiss-las-vegas-avatar-show-revealed-set-to-feature-new-songs', 'https://www.nme.com/wp-content/uploads/2026/04/kiss_classic_lineup.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-14 20:34:36', '2026-04-14 22:27:16.232', '2026-04-14 22:27:16.232', false, 'via NME', NULL);
INSERT INTO public."NewsArticle" VALUES ('cmnz6z4bd001exphpywj4a9cm', 'It looks like Madonna is finally about to launch ‘Confessions On A Dancefloor II’', 'it-looks-like-madonna-is-finally-about-to-launch-confessions-on-a-dancefloor-ii', 'It seems that Madonna is finally preparing to launch her long-awaited new album ‘Confessions On A Dancefloor II’. READ MORE: The Big Read – Madonna: ”People pick on me. That’s just the way it is” The Queen of Pop has been teasing a follow-up to her seminal 2005 record for over a year, telling fans last February that she was “putting my heart and soul into my new music” and signing off the post with “Confessions Part 2”. That was...', 'https://www.nme.com/news/music/it-looks-like-madonna-is-finally-about-to-launch-confessions-on-a-dancefloor-ii-3940340?utm_source=rss&utm_medium=rss&utm_campaign=it-looks-like-madonna-is-finally-about-to-launch-confessions-on-a-dancefloor-ii', 'https://www.nme.com/wp-content/uploads/2026/04/madonna_metgala_2025.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-14 19:28:04', '2026-04-14 22:27:16.249', '2026-04-14 22:27:16.249', false, 'via NME', NULL);
INSERT INTO public."NewsArticle" VALUES ('cmnz6z4bl001fxphp6pay5cbz', 'Kanye West accused of sucker-punching diner at Chateau Marmont and continuing attack while they were unconscious', 'kanye-west-accused-of-sucker-punching-diner-at-chateau-marmont-and-continuing-attack-while-they-were', 'Kanye West has been accused of punching a diner at Los Angeles’ Chateau Marmont in 2024 and continuing the attack while he was unconscious. READ MORE: Donda 2: Kanye West’s ego is scuppering these half-baked, dashed-off sounding songs The lawsuit has been filed in Los Angeles County Superior Court and it sees an unidentified plaintiff accusing the rapper, who now goes by Ye, of battery and infliction of emotional distress. It alleges that the incident occurred at the legendary hotel...', 'https://www.nme.com/news/music/kanye-west-accused-of-sucker-punching-diner-at-chateau-marmont-and-continuing-attack-while-they-were-unconscious-3940332?utm_source=rss&utm_medium=rss&utm_campaign=kanye-west-accused-of-sucker-punching-diner-at-chateau-marmont-and-continuing-attack-while-they-were-unconscious', 'https://www.nme.com/wp-content/uploads/2026/04/kanye_west_2024.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-14 17:52:55', '2026-04-14 22:27:16.257', '2026-04-14 22:27:16.257', false, 'via NME', NULL);
INSERT INTO public."NewsArticle" VALUES ('cmnz6z4bp001gxphpnqzugnyt', 'Tributes pour in for “first lady of Celtic music” Clannad singer Moya Brennan: “She brought the Irish language to the world”', 'tributes-pour-in-for-first-lady-of-celtic-music-clannad-singer-moya-brennan-she-brought-the-irish-la', 'Tributes have been paid after Moya Brennan, lead singer of acclaimed Irish folk group Clannad, passed away aged 73. Nicknamed the “first lady of Celtic music”, she served as the band’s lead vocalist for over five decades and collaborated with the likes of The Rolling Stones‘ Mick Jagger, Led Zeppelin‘s Robert Plant, The Pogues‘ Shane MacGowan and U2 frontman Bono. Known for her haunting sound and resilient defence of Irish Gaelic, her first language, Brennan’s decorated career included wins at...', 'https://www.nme.com/news/music/tributes-pour-in-for-first-lady-of-celtic-music-clannad-singer-moya-brennan-she-brought-the-irish-language-to-the-world-3940326?utm_source=rss&utm_medium=rss&utm_campaign=tributes-pour-in-for-first-lady-of-celtic-music-clannad-singer-moya-brennan-she-brought-the-irish-language-to-the-world', 'https://www.nme.com/wp-content/uploads/2026/04/GETTY_CLANNAD_2000.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-14 16:30:18', '2026-04-14 22:27:16.261', '2026-04-14 22:27:16.261', false, 'via NME', NULL);
INSERT INTO public."NewsArticle" VALUES ('cmnz6z4bu001hxphpu2umc5ae', 'Temples share Justice and Daft Punk-inspired new single ‘Vendetta’: “A modern take on dance music”', 'temples-share-justice-and-daft-punk-inspired-new-single-vendetta-a-modern-take-on-dance-music', 'Temples have dropped the captivating new single ‘Vendetta’, which makes puts a modern spin on electronic music icons like Daft Punk and Justice. READ MORE: Temples tell us about their “Kylie Minogue meets Daft Punk” return on ‘Jet Stream Heart’ and euphoric new album ‘Bliss’ The single is the latest to be shared from the Kettering four-piece’s new album ‘Bliss’, out on June 26 via V2. Pre-order it here. Announced in February with the Kylie Minogue-inspired lead single ‘Jet Stream...', 'https://www.nme.com/news/music/temples-share-justice-and-daft-punk-inspired-new-single-vendetta-a-modern-take-on-dance-music-3940294?utm_source=rss&utm_medium=rss&utm_campaign=temples-share-justice-and-daft-punk-inspired-new-single-vendetta-a-modern-take-on-dance-music', 'https://www.nme.com/wp-content/uploads/2026/04/temples@2000x1270.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-14 15:49:30', '2026-04-14 22:27:16.266', '2026-04-14 22:27:16.266', false, 'via NME', NULL);
INSERT INTO public."NewsArticle" VALUES ('cmnz6z4bx001ixphpjgo1xjhr', 'Damon Albarn leads tributes to “the voice of an angel” and Bollywood icon Asha Bhosle', 'damon-albarn-leads-tributes-to-the-voice-of-an-angel-and-bollywood-icon-asha-bhosle', 'Damon Albarn has paid his respects to Bollywood icon Asha Boshle, saying that she had “the voice of an angel”. READ MORE: Gorillaz – ‘The Mountain’ review: a world-building ode to death and starting over Born in 1933, the Bollywood star was one of the most celebrated Indian singers of all time, recording more than 12,000 songs and earning the nickname ‘Sadi rani’ (Punjabi for “Our Queen”). In her long and storied career she worked with artists including Boy George...', 'https://www.nme.com/news/music/damon-albarn-pays-tribute-to-voice-of-an-angel-bollywood-icon-asha-boshle-3940275?utm_source=rss&utm_medium=rss&utm_campaign=damon-albarn-pays-tribute-to-voice-of-an-angel-bollywood-icon-asha-boshle', 'https://www.nme.com/wp-content/uploads/2026/04/albarn-asha@2000x1270.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-14 15:14:35', '2026-04-14 22:27:16.269', '2026-04-14 22:27:16.269', false, 'via NME', NULL);
INSERT INTO public."NewsArticle" VALUES ('cmnz6z4c0001jxphpe248fizd', '“Black holes” of unclaimed money and crippling bills – Music Venue Trust launch ‘Set The Record Straight’ campaign against PRS', 'black-holes-of-unclaimed-money-and-crippling-bills-music-venue-trust-launch-set-the-record-straight-', 'Music Venue Trust have launched the ‘Set The Record Straight’ campaign against PRS For Music – calling for fairer and more transparent fees, as artists and gig spaces complain of devastating bills and huge “black holes” of unclaimed money. READ MORE: The ticket levy that could save grassroots venues and artists: what happens next? MVT represent hundreds of UK grassroots music venues across the UK, and today (Tuesday April 14) they announced details of ‘Set The Record Straight: Fair Licensing...', 'https://www.nme.com/news/music/prs-artist-venue-royalty-payment-campaign-music-venue-trust-about-3940254?utm_source=rss&utm_medium=rss&utm_campaign=prs-artist-venue-royalty-payment-campaign-music-venue-trust-about', 'https://www.nme.com/wp-content/uploads/2026/04/get_cape_live_1.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-14 14:46:07', '2026-04-14 22:27:16.272', '2026-04-14 22:27:16.272', false, 'via NME', NULL);
INSERT INTO public."NewsArticle" VALUES ('cmnz6z4c3001kxphp1fnoss6z', 'Music fans guessing as record stores are being shipped “mystery vinyl” from a “major artist” with pitched-down vocals', 'music-fans-guessing-as-record-stores-are-being-shipped-mystery-vinyl-from-a-major-artist-with-pitche', 'A “mystery vinyl” with pitched-down vocals has arrived in record stores, and fans are trying to guess which artist is teasing a new release. Shops in the UK and US, including Rough Trade, recently got a new shipment of “mystery” records, which are pressed on vinyl and contain no artist name or title. The cover is a plain white sleeve, and there is nothing printed on the record itself revealing which artist it belongs to. The boxes of vinyl have...', 'https://www.nme.com/news/music/music-fans-guessing-as-record-stores-are-being-shipped-mystery-vinyl-from-a-major-artist-with-pitched-down-vocals-3940264?utm_source=rss&utm_medium=rss&utm_campaign=music-fans-guessing-as-record-stores-are-being-shipped-mystery-vinyl-from-a-major-artist-with-pitched-down-vocals', 'https://www.nme.com/wp-content/uploads/2026/04/records@2000x1270.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-14 13:54:51', '2026-04-14 22:27:16.275', '2026-04-14 22:27:16.275', false, 'via NME', NULL);
INSERT INTO public."NewsArticle" VALUES ('cmnz6z4c6001lxphpn3rerwqq', 'Check out The Rolling Stones’ vinyl-only new single ‘Rough & Twisted’ as The Cockroaches', 'check-out-the-rolling-stones-vinyl-only-new-single-rough-twisted-as-the-cockroaches', 'The Rolling Stones have shared a new vinyl-only single as The Cockroaches, titled ‘Rough & Twisted’. Listen below. Read More: The Rolling Stones – ‘Hackney Diamonds’ review: they’ve still got it The legendary band prompted rumours of their return recently after cryptic posters popped up around London. They featured the name ‘The Cockroaches’ – a past pseudonym used by Mick Jagger and co. – along with a QR code that directed fans to a new website, copyrighted to the Stones’...', 'https://www.nme.com/news/music/check-out-the-rolling-stones-vinyl-only-new-single-rough-twisted-as-the-cockroaches-3940247?utm_source=rss&utm_medium=rss&utm_campaign=check-out-the-rolling-stones-vinyl-only-new-single-rough-twisted-as-the-cockroaches', 'https://www.nme.com/wp-content/uploads/2026/04/TheRollingStonesTheCockroaches-Rough-And-Twisted-single-released.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-14 13:39:57', '2026-04-14 22:27:16.278', '2026-04-14 22:27:16.278', false, 'via NME', NULL);
INSERT INTO public."NewsArticle" VALUES ('cmnz6z4c9001mxphpf1e06d45', 'Jay Weinberg says Slipknot firing “remains confusing”: “My world bottomed out from under me”', 'jay-weinberg-says-slipknot-firing-remains-confusing-my-world-bottomed-out-from-under-me', 'Jay Weinberg has said his firing from Slipknot “remains confusing”, admitting that his “world bottomed out from under [him]” afterwards. The drummer departed the masked metal band in late 2023 after they made a “creative decision” to go in a different direction. Weinberg said he was “heartbroken and blindsided” by the move. READ MORE: Clown talks Slipknot’s 25th anniversary tour and future: “We probably have several albums in us right now” He later shared that the “memories and experiences” from...', 'https://www.nme.com/news/music/jay-weinberg-says-slipknot-firing-remains-confusing-my-world-bottomed-out-from-under-me-3940188?utm_source=rss&utm_medium=rss&utm_campaign=jay-weinberg-says-slipknot-firing-remains-confusing-my-world-bottomed-out-from-under-me', 'https://www.nme.com/wp-content/uploads/2026/04/JayWeinbergSlipknot-comments-news.jpg', false, false, NULL, 'cmnkctw1q000kplhpae6zcf4i', '2026-04-14 12:13:45', '2026-04-14 22:27:16.281', '2026-04-14 22:27:16.281', false, 'via NME', NULL);
