INSERT INTO public."Event" VALUES ('cmnw9z2zh009uwvhpilz24ld4', 'The Great Escape Festival 2026', 'FESTIVAL', 'The Great Escape Festival', 'Various Brighton Venues', 'Brighton', 'GB', '2026-05-13 00:00:00', '2026-05-16 00:00:00', 'https://www.ticketmaster.co.uk/the-great-escape-festival-2026-brighton-13-05-2026/event/1F0062A9A2AD11BF', NULL, 'Various venues across Brighton Ages 18+ The Great Escape is the festival for new music, showcasing emerging artists from all over the world in 30+ walkable venues across the city and a pop-up festival site on Brighton Beach. It''s the first place to discover your new favourite artist and see them in an intimate setting before they go on to headline major festival stages. TGE is also attended by the music industry who are on the hunt for the next big thing. We run a conference alongside the gigs featuring insightful panels, topical debates, keynote speeches and networking opportunities in abundance. The Alternative Escape, our Spotlight Shows, secret gigs, club nights and spontaneous collaborations all add to the festivities and make this weekend in Brighton one not to miss.', 'https://s1.ticketm.net/dam/a/a75/bfd02fc8-ac77-47c7-8621-245277b9fa75_TABLET_LANDSCAPE_16_9.jpg', NULL, 'TICKETMASTER', 'G5vHZbnEtyKGO', 'tm-the-great-escape-festival-various-brighton-venues-brighton-2026-05-13', 50.821984, -0.138208, true, '2026-04-12 21:27:54.845', '2026-04-12 21:27:54.85', NULL, NULL, NULL, NULL, NULL, false, 'https://www.facebook.com/greatescapefestival', 'https://www.instagram.com/greatescapefest/', NULL, NULL, 'https://twitter.com/thegreatescape', 'https://greatescapefestival.com/', NULL, false, false);
