INSERT INTO public."Event" VALUES ('cmnm77yqs0031p4hpjme5vwsh', 'Christy: a Concert In Support of Women''s Aid', 'CONCERT', 'Christy Moore', 'Vicar Street', 'Dublin', 'IE', '2026-04-19 00:00:00', NULL, 'https://www.ticketmaster.ie/christy-a-concert-in-support-of-dublin-19-04-2026/event/1800643792F1B086', NULL, 'Rescheduled from 8th March 2026 - Original tickets remain valid. Over 18s - ID Required. Ground Floor Fully Seated Women''s Aid is a national organisation working to prevent and address the impact of domestic violence and abuse since 1974. They do this by advocating, influencing, training, and campaigning for effective responses to reduce the scale and impacts of domestic abuse on women and children and providing high-quality, specialised, integrated support services. In 2024, Women''s Aid national and regional frontline services were contacted 32,144 times, an increase of 12% on 2023. These are the highest co ntact rates in the organisation''s 50-year history. www.womensaid.ie For more concert information see www.aikenpromotions.com', 'https://s1.ticketm.net/dam/a/a41/689d6fb6-72f7-47b4-a27a-f1cd01e99a41_RETINA_PORTRAIT_16_9.jpg', 'Folk', 'TICKETMASTER', '16vOZ_dr3G7Hhek', 'tm-christy-moore-vicar-street-dublin-2026-04-19', 53.34194316, -6.27717376, true, '2026-04-05 20:13:08.644', '2026-04-14 22:28:08.656', NULL, NULL, NULL, '20:00:00', 'Indie Folk', false, 'https://www.facebook.com/officialchristymoore', NULL, 'https://open.spotify.com/artist/3Ebn7mKYzD0L3DaUB1gNJZ', NULL, 'https://twitter.com/christymoore45', 'http://www.christymoore.com/', 'https://www.youtube.com/user/ChristyMooreMusic', false, false);
